import commentClassification from './comment-classification.mjs';
import referenceIntegrity from './reference-integrity.mjs';
import markdownLinkLabels from './markdown-link-labels.mjs';
import taskLifecycle from './task-lifecycle.mjs';
import warningSuppression from './warning-suppression.mjs';
import filePlacement from './file-placement.mjs';
import squashMergeHistory from './squash-merge-history.mjs';
import claudeMdLength from './claude-md-length.mjs';
import generatedMergeDriver from './generated-merge-driver.mjs';
import sharedConstants from './shared-constants.mjs';
import skillOwnership from './skill-ownership.mjs';
import catalogCompleteness from './catalog-completeness.mjs';
import claudiniteIsolation from './claudinite-isolation.mjs';
import baselining from './run_daily/baselining.mjs';

// The baseline pack: working discipline, the task lifecycle, and the core
// checks. Declared explicitly like every other pack — no pack is active by
// default. Bootstrap's --init seeds the declaration and the nightly baselining
// backfills it into existing consumers; never fingerprinted (the declaration is
// authoritative — dropping it is a deliberate choice).
export default {
  id: 'basics',
  detect: null,
  marker: null,
  seededByDefault: true,
  prose: 'RULES.md',
  rules: [
    commentClassification,
    referenceIntegrity,
    markdownLinkLabels,
    taskLifecycle,
    warningSuppression,
    filePlacement,
    squashMergeHistory,
    claudeMdLength,
    generatedMergeDriver,
    sharedConstants,
    skillOwnership,
    catalogCompleteness,
    claudiniteIsolation,
  ],
  // The skills every project's work can call for, whatever its technology —
  // mounted wherever basics is declared (which --init seeds everywhere) by
  // skills/mount-skills.mjs. When one of these stops being a baseline
  // activity, move it to the pack whose projects need it; the skill-ownership
  // check keeps the whole catalog required by some pack.
  skills: [
    'adopt-claudinite',
    'authoring-agent-docs',
    'bug-investigation',
    'bump-version',
    'engineering-practices',
    'file-placement',
    'generate-project-instructions',
    'git-github-advanced',
    'lessons-learned',
    'merge-to-main',
    'repo-text-sweeps',
    'unattended-agents',
    'writing-tests',
  ],
  // The baseline daily task every member runs: baselining (re-run the idempotent
  // bootstrap + check-alignment). Being in basics — declared everywhere — makes it
  // fleet-universal without a fleet-core category.
  run_daily: [baselining],
};
---BARRIERS---
import barrier from './check.mjs';

// The barriers pack — enforce a directed folder-access graph. A declared pack
// (no fingerprint: wanting structural segregation is a project's own call, and
// another pack can pull it in via `requires`), it ships one config-driven check
// reading the repo's graph from .claudinite-checks.json `packConfig.barriers`.
// Its detection engine (engine.mjs) is exported so other packs can compose a
// fixed barrier of their own — the mechanism this pack exists to provide. No
// prose: the finding is the instruction, and the full guide is the README.
//
// Adopting barriers without a graph is a silent no-op, so adoption asks what
// the barriers are FOR (packs/interview.mjs) — the guided on-ramp beats both
// running empty and guessing separations from existing state.
export default {
  id: 'barriers',
  detect: null,
  marker: null,
  prose: null,
  questions: [{
    id: 'goals',
    prompt: 'What should these barriers accomplish — which folders must never reference which (imports, paths, docs included), and what architectural boundary does each separation protect?',
    distill: 'derive the directed edge list into this entry\'s config as { "rules": [{ "from": "<dir>", "to": "<dir>" }] }; if no separation is wanted yet, record that as the answer and leave config unset',
  }],
  rules: [barrier],
};
---PRODUCTWIKI---
// Project-aspect standard pack: the self-growing product research wiki
// (compile-once/refine-in-place, cited, dated, isolated behind the reviewed
// product-requirements crossing point). The folder is the classifier: the two
// reserved names (product-requirements/, sample-data/) have fixed meaning;
// everything else under product-wiki/ is wiki space. Fingerprinted by the
// standard's one structural constant — the sink.
import { SINK_README } from './lib.mjs';
import layout from './layout.mjs';
import pageSections from './page-sections.mjs';
import growthLog from './growth-log.mjs';
import sources from './sources.mjs';
import freshness from './freshness.mjs';
import isolation from './isolation.mjs';
import wikiGrowth from './run_daily/wiki-growth.mjs';

export default {
  id: 'product-wiki',
  marker: SINK_README,
  detect: (ctx) => ctx.tracked.includes(SINK_README),
  prose: 'RULES.md',
  rules: [layout, pageSections, growthLog, sources, freshness, isolation],
  run_daily: [wikiGrowth],
};

