1	import { test } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { mkdtempSync, mkdirSync, writeFileSync, copyFileSync } from 'node:fs';
4	import { tmpdir } from 'node:os';
5	import { join, dirname } from 'node:path';
6	import { fileURLToPath, pathToFileURL } from 'node:url';
7	
8	// This test lives at <repo>/mount/vendor.test.mjs.
9	const MOUNT_DIR = dirname(fileURLToPath(import.meta.url));
10	const REPO_ROOT = dirname(MOUNT_DIR);
11	
12	function writeAt(root, rel, content) {
13	  mkdirSync(dirname(join(root, rel)), { recursive: true });
14	  writeFileSync(join(root, rel), content);
15	}
16	
17	// A hermetic canon mirroring the real layout: the REAL vendor.mjs and the REAL
18	// packs/registry.mjs it imports (both self-locate relative to their own file),
19	// a small engine tree with the things that must be EXCLUDED present (tests,
20	// engine-root docs, preferences), and fixture packs/skills — so the tests
21	// exercise the structural-discovery contract, not the live corpus's contents.
22	function makeCanon({ packs = [], skills = [] } = {}) {
23	  const root = mkdtempSync(join(tmpdir(), 'claudinite-vendor-'));
24	  mkdirSync(join(root, 'mount'), { recursive: true });
25	  mkdirSync(join(root, 'packs'), { recursive: true });
26	  copyFileSync(join(MOUNT_DIR, 'vendor.mjs'), join(root, 'mount', 'vendor.mjs'));
27	  copyFileSync(join(REPO_ROOT, 'packs', 'registry.mjs'), join(root, 'packs', 'registry.mjs'));
28	  writeAt(root, 'CLAUDE.md', 'index\n');
29	  // engine roots: real-shaped content plus everything that must stay out
30	  writeAt(root, 'checks/run.mjs', 'stub\n');
31	  writeAt(root, 'checks/lib/context.mjs', 'stub\n');
32	  writeAt(root, 'checks/README.md', 'canon doc\n');
33	  writeAt(root, 'checks/test/runner.test.mjs', 'stub\n');
34	  writeAt(root, 'mount/session-start.sh', 'stub\n');
35	  writeAt(root, 'mount/DESIGN.md', 'canon doc\n');
36	  // machinery roots: top-level .mjs picked up, tests and dirs' docs not
37	  writeAt(root, 'packs/load-active-prose.mjs', 'stub\n');
38	  writeAt(root, 'packs/env.mjs', 'stub\n');
39	  writeAt(root, 'packs/env.test.mjs', 'stub\n');
40	  writeAt(root, 'packs/README.md', 'canon doc\n');
41	  writeAt(root, 'skills/registry.mjs', 'stub\n');
42	  writeAt(root, 'skills/mount-skills.mjs', 'stub\n');
43	  writeAt(root, 'skills/README.md', 'canon doc\n');
44	  // per-user content: must never appear in any vendor set
45	  writeAt(root, 'preferences/owner@example.com.md', 'prefs\n');
46	  for (const { id, requires = [], skills: skl = [], extraFiles = [] } of packs) {
47	    writeAt(root, `packs/${id}/pack.mjs`,
48	      `export default { id: ${JSON.stringify(id)}, requires: ${JSON.stringify(requires)}, skills: ${JSON.stringify(skl)} };\n`);
49	    for (const file of extraFiles) writeAt(root, `packs/${id}/${file}`, `stub ${file}\n`);
50	  }
51	  for (const { name, files = ['SKILL.md'] } of skills) {
52	    for (const file of files) writeAt(root, `skills/${name}/${file}`, 'stub\n');
53	  }
54	  return root;
55	}
56	
57	const vendorAt = async (root, declared, opts) =>
58	  (await import(pathToFileURL(join(root, 'mount', 'vendor.mjs')).href))
59	    .computeVendorSet(declared, opts);
60	
61	const FIXTURE = {
62	  packs: [
63	    { id: 'alpha', skills: ['s1'], extraFiles: ['RULES.md', 'check.mjs', 'pack.test.mjs', 'stubs/wf.yml'] },
64	    { id: 'beta', requires: ['gamma'] },
65	    { id: 'gamma', skills: ['s2'] },
66	  ],
67	  skills: [
68	    { name: 's1', files: ['SKILL.md', 'helper.test.mjs'] },
69	    { name: 's2' },
70	  ],
71	};
72	
73	test('structural set: engine roots + machinery + declared pack + its skills, exact; tests, engine docs, preferences all out', async () => {
74	  const root = makeCanon(FIXTURE);
75	  // entry-object form must work like a bare id (packEntryId handles both)
76	  const { files, errors } = await vendorAt(root, [{ id: 'alpha', config: { k: 1 } }]);
77	  assert.deepEqual(errors, []);
78	  const expected = [
79	    'CLAUDE.md',
80	    'checks/lib/context.mjs',
81	    'checks/run.mjs',
82	    'mount/session-start.sh',
83	    'mount/vendor.mjs',
84	    'packs/env.mjs',
85	    'packs/load-active-prose.mjs',
86	    'packs/registry.mjs',
87	    'skills/mount-skills.mjs',
88	    'skills/registry.mjs',
89	    'packs/alpha/RULES.md',
90	    'packs/alpha/check.mjs',
91	    'packs/alpha/pack.mjs',
92	    'packs/alpha/stubs/wf.yml',
93	    'skills/s1/SKILL.md',
94	  ].sort();
95	  assert.deepEqual(files, expected);
96	  // The owner-decided exclusions, asserted by name so a regression reads clearly:
97	  assert.ok(!files.some((f) => f.startsWith('preferences/')), 'per-user preferences must never vendor');
98	  assert.ok(!files.some((f) => f.endsWith('README.md') || f.endsWith('DESIGN.md')), 'engine-root docs stay canon-side');
99	  assert.ok(!files.some((f) => f.includes('.test.mjs') || f.startsWith('checks/test/')), 'tests stay canon-side');
100	});
101	
102	test('a pack .md is payload and vendors even though engine-root .md does not', async () => {
103	  const root = makeCanon(FIXTURE);
104	  const { files } = await vendorAt(root, ['alpha']);
105	  assert.ok(files.includes('packs/alpha/RULES.md'));
106	  assert.ok(!files.includes('packs/README.md'));
107	});
108	
109	test('requires closure pulls the dependency pack and its skills in', async () => {
110	  const root = makeCanon(FIXTURE);
111	  const { files, errors } = await vendorAt(root, ['beta']);
112	  assert.deepEqual(errors, []);
113	  assert.ok(files.includes('packs/beta/pack.mjs'));
114	  assert.ok(files.includes('packs/gamma/pack.mjs'));
115	  assert.ok(files.includes('skills/s2/SKILL.md'));
116	  assert.ok(!files.some((f) => f.startsWith('packs/alpha/')));
117	});
118	
119	test('ids naming no canon pack (local packs, typos) are skipped without error', async () => {
120	  const root = makeCanon(FIXTURE);
121	  const { files, errors } = await vendorAt(root, ['alpha', 'my-local-pack']);
122	  assert.deepEqual(errors, []);
123	  assert.ok(!files.some((f) => f.includes('my-local-pack')));
124	});
125	
126	test('a pack-required skill missing from the tree is an error; the set still computes', async () => {
127	  const root = makeCanon({ packs: [{ id: 'delta', skills: ['ghost'] }] });
128	  const { files, errors } = await vendorAt(root, ['delta']);
129	  assert.equal(errors.length, 1);
130	  assert.match(errors[0].what, /"ghost"/);
131	  assert.match(errors[0].what, /delta/);
132	  assert.ok(files.includes('packs/delta/pack.mjs'));
133	});
134	
135	test('extraSkills adds skills the canon cannot derive (a local pack\'s requirements)', async () => {
136	  const root = makeCanon(FIXTURE);
137	  const { files, errors } = await vendorAt(root, ['beta'], { extraSkills: ['s1'] });
138	  assert.deepEqual(errors, []);
139	  assert.ok(files.includes('skills/s1/SKILL.md'));
140	  assert.ok(!files.includes('skills/s1/helper.test.mjs'));
141	});
