1	import { finding } from '../../checks/lib/findings.mjs';
2	import { under } from '../barriers/engine.mjs';
3	
4	// Shared helpers and the standard's path constants — spelled ONCE here so the
5	// checks, the manifest, and the barrier can't drift apart. The wiki set is
6	// STRUCTURAL, not configured: a wiki page is a README.md at depth >= 2 under
7	// product-wiki/, outside the two reserved subtrees (product-requirements/ — the
8	// human-reviewed sink — and sample-data/ — illustrative assets). No wikis
9	// manifest exists anywhere, so a renamed or newly added wiki folder is
10	// classified correctly with nothing to drift (folder-is-the-classifier).
11	export const PRODUCT_ROOT = 'product-wiki';
12	export const SINK_DIR = 'product-wiki/product-requirements';
13	export const SAMPLE_DATA_DIR = 'product-wiki/sample-data';
14	export const INDEX_README = 'product-wiki/README.md';
15	export const SINK_README = 'product-wiki/product-requirements/README.md';
16	
17	export function wikiPages(files) {
18	  return files.filter(
19	    (f) => /^product-wiki\/.+\/README\.md$/.test(f) && !under(f, SINK_DIR) && !under(f, SAMPLE_DATA_DIR)
20	  );
21	}
22	
23	// One bullet/date grammar for every check that reads a growth log: a top-level
24	// bullet (-, * or + at column 0) leading with its YYYY-MM-DD run date, bold or
25	// plain — the invariant is dating, not typography. Date.UTC ROLLS OVER
26	// out-of-range parts (2026-02-30 → March 2) instead of failing, so calendar
27	// validity needs the explicit round-trip below.
28	export const BULLET = /^[-*+]\s/;
29	export const DATED = /^[-*+]\s+(?:\*\*)?(\d{4})-(\d{2})-(\d{2})(?:\*\*)?\b/;
30	export function realDateUTC(y, mo, d) {
31	  const dt = new Date(Date.UTC(y, mo - 1, d));
32	  return dt.getUTCFullYear() === y && dt.getUTCMonth() === mo - 1 && dt.getUTCDate() === d
33	    ? dt.getTime() : null;
34	}
35	
36	// Blank out fenced code blocks, preserving line count — a template embedded in
37	// a ``` fence must neither satisfy a section requirement nor feed bullets into
38	// the section scans. Every section reader below works on the stripped text.
39	function stripFences(text) {
40	  let inFence = false;
41	  return text.split('\n').map((l) => {
42	    if (/^\s*(```|~~~)/.test(l)) { inFence = !inFence; return ''; }
43	    return inFence ? '' : l;
44	  });
45	}
46	
47	const headingRe = (name) => new RegExp(`^##\\s+${name}\\b`, 'i');
48	
49	// Does the page carry a real (non-fenced) `## <name>` section heading?
50	// The single definition of the heading contract — sectionBody anchors on the
51	// same regex, so "present" and "readable" can never disagree.
52	export function hasSection(text, name) {
53	  const re = headingRe(name);
54	  return stripFences(text).some((l) => re.test(l));
55	}
56	
57	// The lines of the `## <name>` section (case-insensitive; suffix words after
58	// the name are fine — "## Open questions (for the next pass)") up to the next
59	// `## ` heading or EOF, fenced content blanked. Each entry carries its
60	// 1-indexed file line so findings can pin the offending bullet. Returns null
61	// when the heading is absent — callers skip then, because the missing heading
