30	// .gitattributes) — third-party or machine-written content, not the project's own
31	// code. `buildContext` drops these from the default `ctx.files`, so every check that
32	// reasons about "the project's code" skips them for free: a suppression marker inside
33	// a recorded fixture, a placement "violation" in a generated artifact, and a dangling
34	// link in a vendored doc are none of them the project's decision. `git check-attr`
35	// honors .gitattributes patterns/precedence natively (paths on stdin so a large repo
36	// can't overflow the arg list). The unfiltered set stays on `ctx.allFiles` for the one
37	// check that reasons *about* generated files (generated-merge-driver).
38	function vendoredSet(root, files) {
39	  const set = new Set();
40	  if (!files.length) return set;
41	  const out = sh(root, 'git', ['check-attr', '--stdin', 'linguist-vendored', 'linguist-generated'],
42	    { allowFail: true, input: files.join('\n') + '\n' });
43	  for (const line of (out || '').split('\n')) {
44	    const m = /^(.*): (?:linguist-vendored|linguist-generated): (.*)$/.exec(line);
45	    if (m && m[2] === 'set') set.add(m[1]);
46	  }
