50	// The complete set of top-level settings .claudinite-checks.json may carry. A key
51	// outside this set is a typo or a stale name — a settings error as real as invalid
52	// JSON, caught at load so it can't silently change nothing. `packConfig` is the
53	// legacy home of per-pack parameters — still honored while the fleet migrates to
54	// pack-entry `config` (the baselining folds it in), no longer documented. The
55	// `pack-entry-config` baseline migration (migrations/active_migrations/) tracks
56	// the fleet's convergence; when it retires, drop the key here (and the overlay
57	// below) so a straggler gets the unknown-setting error.
58	// `claudinite` is the vendored-mount stamp — { updated: "<ISO datetime>", ref: "<sha>" },
59	// written by the nightly update pass, selecting which migration notes still apply
60	// (mount/DESIGN.md owns the model); the checks engine itself only tolerates it.
61	export const CONFIG_KEYS = ['packs', 'rules', 'accept', 'sharedConstants', 'packConfig', 'maintenance', 'claudinite'];
62	
63	// The properties a `packs` entry object may carry: the pack's parameters
64	// (`config`), its adoption-interview answers (`answers` — the owner's verbatim
65	// responses to the questions the pack declares on its pack.mjs, keyed by
66	// question id; packs/interview.mjs), and the rule overrides / acceptances that
67	// exist BECAUSE this pack is declared (`rules`, `accept` — they may name any
68	// rule; the entry is their provenance). `via` is written by
69	// resolveDeclaredPacks on materialized dependencies (packs/registry.mjs).
70	export const PACK_ENTRY_KEYS = ['id', 'config', 'answers', 'rules', 'accept', 'via'];
71	
72	// Load and validate the project's settings. Validity is checked at load — the
73	// moment Claudinite reads the file — and every problem is collected into `errors`
74	// (each `{ what, fix }`), the runner's single settings-validity gate. A wrong
75	// property name, malformed JSON, and a wrong pack name are all equally settings
76	// errors; unknown *pack* names need the registry, so the runner adds those (it
77	// holds the known-pack list). On unparsable/misshaped JSON the usable fields fall
78	// back to empty so the rest of a sweep still runs, with the error reported.
79	//
80	// The returned shape is NORMALIZED: `packs` is plain ids, `rules` and `accept`
81	// are the top-level and per-entry settings merged (an entry-sourced acceptance
82	// carries `pack: <id>` as provenance; conflicting severity overrides are a
83	// settings error), and `packConfig` is the per-pack parameter view — each
84	// entry's `config`, overlaid on the legacy top-level key. Checks and env
85	// machinery read this one shape regardless of which form the file used.
86	export function loadConfig(root) {
87	  const path = join(root, '.claudinite-checks.json');
88	  const empty = { packs: [], packEntries: [], rules: {}, accept: [], sharedConstants: [], packConfig: {}, errors: [] };
89	  if (!existsSync(path)) return empty;
90	
91	  let raw;
92	  try {
93	    raw = JSON.parse(readFileSync(path, 'utf8'));
94	  } catch (e) {
95	    return { ...empty, errors: [{ what: `.claudinite-checks.json is not valid JSON: ${e.message}`, fix: 'fix the JSON syntax' }] };
96	  }
97	  if (raw === null || typeof raw !== 'object' || Array.isArray(raw)) {
98	    return { ...empty, errors: [{ what: '.claudinite-checks.json must be a JSON object', fix: 'wrap the settings in an object: { "packs": [ ... ] }' }] };
99	  }
100	
101	  const errors = [];
102	  for (const key of Object.keys(raw)) {
103	    if (!CONFIG_KEYS.includes(key)) {
104	      errors.push({ what: `unknown setting "${key}"`, fix: `remove it or fix the name — valid settings: ${CONFIG_KEYS.join(', ')}` });
105	    }
106	  }
107	
108	  // --- packs: each entry a pack id or { id, config?, rules?, accept?, via? } ---
109	  const packs = [];
110	  const packEntries = [];
111	  for (const entry of Array.isArray(raw.packs) ? raw.packs : []) {
112	    if (typeof entry === 'string') {
113	      packs.push(entry);
114	      packEntries.push({ id: entry });
115	      continue;
116	    }
117	    if (entry === null || typeof entry !== 'object' || Array.isArray(entry)) {
