203	export function buildContext({ root, mode = 'changed', baseOverride = null, transcriptPath = null }) {
204	  root = resolve(root);
205	  const baseRef = baseOverride || resolveBaseRef(root);
206	  const mergeBase = baseRef ? (gitTry(root, 'merge-base', 'HEAD', baseRef) || '').trim() || null : null;
207	  // Diffing against HEAD keeps uncommitted work in scope even when no base branch resolves.
208	  const diffBase = mergeBase || 'HEAD';
209	
210	  const tracked = lines(gitTry(root, 'ls-files'));
211	  const untracked = lines(gitTry(root, 'ls-files', '--others', '--exclude-standard'));
212	
213	  let scanned;
214	  if (mode === 'all') {
215	    scanned = [...tracked, ...untracked];
216	  } else {
217	    const vsBase = lines(gitTry(root, 'diff', '--name-only', '--diff-filter=d', diffBase));
218	    scanned = [...new Set([...vsBase, ...untracked])];
219	  }
220	  // The vendored corpus under the shared mount is canon-owned, never the
221	  // project's own code — structurally out of scope for every check, on any git
222	  // host and any checkout (deliberately not attribute-driven). The consumer's
223	  // own .claudinite/local_packs/ sits BESIDE the shared mount and stays fully
224	  // in scope.
225	  // git emits '/'-separated paths on every platform; SHARED_SUBDIR is joined
226	  // with the platform separator, so normalize before prefix-matching.
227	  const sharedPrefix = `${SHARED_SUBDIR.split(sep).join('/')}/`;
228	  scanned = scanned.filter((f) => !f.startsWith(sharedPrefix));
229	  // Every in-scope regular file, vendored/generated included.
230	  const allFiles = scanned.filter((f) => existsSync(join(root, f)) && statSync(join(root, f)).isFile());
231	  // The default sweep excludes vendored/generated files, so `ctx.files` is the
232	  // project's OWN authored code and every check skips them for free (see vendoredSet).
233	  const vendored = vendoredSet(root, allFiles);
234	  const files = allFiles.filter((f) => !vendored.has(f));
235	
236	  const deleted = mergeBase ? lines(gitTry(root, 'diff', '--name-only', '--diff-filter=D', mergeBase)) : [];
237	
