1	import { finding } from '../../checks/lib/findings.mjs';
2	import { classifiedTurns } from '../../checks/lib/transcript.mjs';
3	
4	// The canonical home of the executable spec. A project whose spec lives elsewhere
5	// declares the path on its executable-requirements pack entry (`config.spec`), so
6	// the check enforces ordering against the REAL spec instead of a path the project
7	// doesn't use.
8	const DEFAULT_SPEC = 'dev/requirements/requirements.md';
9	
10	// A file whose change is product work rather than specification: anything that
11	// is neither markdown nor part of the requirements tree. Goldens and harness
12	// code under dev/requirements/ count as the spec's own machinery, not "code
13	// before the spec".
14	const isCode = (f) => !f.endsWith('.md') && !f.startsWith('dev/requirements/');
15	
16	// The spec path this project actually uses: its configured value, else canonical.
17	function specPath(ctx) {
18	  const configured = ctx.config?.packConfig?.['executable-requirements']?.spec;
19	  return typeof configured === 'string' && configured ? configured : DEFAULT_SPEC;
20	}
21	
22	// Conversation-surface rule enforcing the feature run's doc-first ordering on
23	// the branch: after the owner's latest feature-classified comment, an
24	// independent commit updating the spec (no code alongside) must precede the
25	// first code commit. Scoped by the comment's timestamp so earlier work already
26	// on the branch — a previous task, a previous run — is never re-litigated.
27	const rule = {
28	  id: 'feature-requirements-first',
29	  severity: 'blocking',
30	  description: 'A feature run must land an independent requirements-doc commit before its first code commit',
31	  doc: 'packs/executable-requirements/RULES.md',
32	  why: 'the feature run is doc-first: the spec change is the requirement\'s durable home and must precede the code that satisfies it',
33	
34	  run(ctx) {
35	    const entries = ctx.conversation();
36	    if (!entries) return [];
37	    const featureTurns = classifiedTurns(entries).filter((t) => t.classes.has('feature'));
38	    if (!featureTurns.length) return [];
39	
40	    // A check-the-work rule must be satisfiable by doing the work right. If the spec
41	    // it would enforce ordering against isn't in the repo at all (a non-canonical
42	    // layout that hasn't declared its path, or the pack pulled in via `requires`
43	    // without the canonical file), no commit could ever satisfy it — firing would
44	    // force the wrong remedy: an `accept` (a check-the-WORLD instrument, which a
45	    // successive run wouldn't even re-find) or a post-hoc rebase. Self-skip instead
46	    // of emitting a finding no correct work can clear.
47	    const spec = specPath(ctx);
48	    if (!ctx.exists(spec)) return [];
49	
50	    const since = Date.parse(featureTurns[featureTurns.length - 1].timestamp ?? '') || 0;
51	
52	    let specSeen = false;
53	    for (const commit of ctx.commitsWithFiles()) {
54	      if ((Date.parse(commit.date) || 0) < since) continue;
