36	function walk(relDir, files, errors, { engine = false } = {}) {
37	  let entries;
38	  try {
39	    entries = readdirSync(join(canonRoot, relDir), { withFileTypes: true });
40	  } catch (e) {
41	    errors.push({
42	      what: `${relDir} is not a readable directory in the canon tree: ${e.message}`,
43	      fix: `restore ${relDir}, or fix what names it (an engine root, a pack.mjs skills list)`,
44	    });
45	    return;
46	  }
47	  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
48	    if (entry.isDirectory()) {
49	      if (engine && entry.name === 'test') continue;
50	      walk(`${relDir}/${entry.name}`, files, errors, { engine });
51	    } else if (!isTest(entry.name) && !(engine && entry.name.endsWith('.md'))) {
52	      files.add(`${relDir}/${entry.name}`);
53	    }
54	  }
55	}
