57	// declaredEntries: the raw `packs` array from .claudinite-checks.json (id
58	// strings and/or entry objects). extraSkills: skills the canon can't derive —
59	// e.g. ones a member's own local packs require. Returns { files, errors }:
60	// sorted canon-relative paths, and { what, fix } diagnostics. Ids naming no
61	// canon pack (a consumer's local packs, or a typo the runner's settings
62	// validation already flags) are skipped without error; per-user preferences
63	// are deliberately absent — they are never vendored (DESIGN.md).
64	export async function computeVendorSet(declaredEntries, { extraSkills = [] } = {}) {
65	  const files = new Set();
66	  const errors = [];
67	
68	  if (existsSync(join(canonRoot, INDEX_FILE))) files.add(INDEX_FILE);
69	  else errors.push({ what: `${INDEX_FILE} is missing from the canon tree`, fix: 'restore the corpus index' });
70	  for (const root of ENGINE_DIR_ROOTS) walk(root, files, errors, { engine: true });
71	  for (const root of MACHINERY_ROOTS) {
72	    let entries;
73	    try {
74	      entries = readdirSync(join(canonRoot, root), { withFileTypes: true });
75	    } catch (e) {
76	      errors.push({ what: `${root} is not a readable directory in the canon tree: ${e.message}`, fix: `restore ${root}` });
77	      continue;
78	    }
79	    for (const entry of entries) {
80	      if (entry.isFile() && entry.name.endsWith('.mjs') && !isTest(entry.name)) files.add(`${root}/${entry.name}`);
81	    }
82	  }
83	
84	  const packs = await loadPacks();
85	  const byId = new Map(packs.map((p) => [p.id, p]));
86	  const ids = [];
87	  for (const entry of resolveDeclaredPacks(declaredEntries ?? [], packs)) {
88	    const id = packEntryId(entry);
89	    if (id !== undefined && byId.has(id) && !ids.includes(id)) ids.push(id);
90	  }
91	  for (const id of ids) walk(`packs/${id}`, files, errors);
92	
93	  const requiredBy = new Map(extraSkills.map((s) => [s, ['extraSkills']]));
94	  for (const id of ids) {
95	    for (const skill of byId.get(id).skills ?? []) {
96	      requiredBy.set(skill, [...(requiredBy.get(skill) ?? []), id]);
97	    }
98	  }
99	  for (const [skill, requirers] of [...requiredBy].sort(([a], [b]) => a.localeCompare(b))) {
100	    if (existsSync(join(canonRoot, 'skills', skill))) walk(`skills/${skill}`, files, errors);
101	    else errors.push({
102	      what: `skill "${skill}" (required by ${requirers.join(', ')}) is missing from skills/`,
103	      fix: 'restore the skill, or drop it from the requirer\'s skills list',
104	    });
105	  }
106	
107	  return { files: [...files].sort(), errors };
108	}

