    '.claudinite-checks.json': '{ "packs": ["product-wiki"], "accept": [ { "rule": "product-wiki-isolation", "path": "product-wiki/Market/README.md", "reason": "r" } ] }\n',
  });
  assert.deepEqual(f, []);
});

